import numpy as np

class Checkers:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.initialize_board()
        self.current_player = 1

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in (0, 2, 4, 6):
                self.board[i, j] = -1
        for i in range(5, 8):
            for j in (1, 3, 5, 7):
                self.board[i, j] = 1

    def print_board(self):
        # Print the current board state
        print('   a b c d e f g h')
        for i in range(8):
            print(f'{i} ', end='')
            for j in range(8):
                if self.board[i, j] == -1:
                    print(' x', end='')
                elif self.board[i, j] == 1:
                    print(' o', end='')
                else:
                    print(' .', end='')
            print()

    def move_piece(self, from_pos, to_pos):
        # Move a piece from one position to another
        x_from, y_from = self._convert_to_index(from_pos)
        x_to, y_to = self._convert_to_index(to_pos)
        if self.board[x_from, y_from] == 0:
            raise ValueError('No piece at the specified from position.')
        if (x_to - x_from) not in [-1, 1] or abs(y_to - y_from) != 1:
            raise ValueError('Invalid move. Only one step diagonally allowed.')
        self.board[x_to, y_to] = self.board[x_from, y_from]
        self.board[x_from, y_from] = 0
        self.current_player *= -1

    def _convert_to_index(self, pos):
        # Convert from a to h and 0 to 7 to board indices
        col = ord(pos[0]) - ord('a')
        row = int(pos[1])
        return row, col

if __name__ == '__main__':
    game = Checkers()
    while True:
